sql:
SELECT audit_type, status
FROM audit_reports
WHERE entity = 'MINUSCA';

external_knowledge:
- "seeds of transformation": refers to the recommendations that are open and not fully implemented;
- "fully bloom": when a recommendation reaches 100% completion;
- "documents sown in the last lunar cycle": reports finalized within the last month;
- "nurturing phase and haven't reached full maturity": recommendations with implementation completion less than 100%;
- "financial guardians": audit teams whose name includes the word 'Financial'.

sql:
SELECT entities.entity_name, audit_reports.report_title, audit_reports.issue_date
FROM entities
JOIN audit_reports ON entities.entity_id = audit_reports.entity;
